171→interface SnippetFormState {
172→  name: string;
173→  keyword: string;
174→  snippet: string;
175→  category: SnippetCategory;
176→  tags: string[];
177→}
178→
179→const INITIAL_SNIPPET_FORM: SnippetFormState = {
