187→const FORM_TAG_OPTIONS = SNIPPET_TAGS.map(t => ({
188→  label: t.label,
189→  value: t.value,
190→}));
191→
192→const FORM_CATEGORY_OPTIONS = SNIPPET_CATEGORIES.map(c => ({
