202→function EditSnippetView({ snippet, onSubmit }: EditSnippetViewProps) {
203→  const [form, setForm] = useState<SnippetFormState>(() => {
204→    if (snippet) {
205→      return {
206→        name: snippet.name,
207→        keyword: snippet.keyword,
208→        snippet: snippet.content,
209→        category: snippet.category,
210→        tags: snippet.tags.map(t => t.text.toLowerCase()),
211→      };
212→    }
213→    return INITIAL_SNIPPET_FORM;
214→  });
215→  const [errors, setErrors] = useState<
216→    Partial<Record<keyof SnippetFormState, string>>
217→  >({});
218→
219→  const handleSubmit = useCallback(() => {
220→    const newErrors: Partial<Record<keyof SnippetFormState, string>> = {};
221→    if (!form.name.trim()) {
222→      newErrors.name = 'Name is required';
223→    }
224→    if (!form.snippet.trim()) {
225→      newErrors.snippet = 'Snippet content is required';
226→    }
227→    setErrors(newErrors);
228→    if (Object.keys(newErrors).length > 0) return;
229→    onSubmit(form);
230→  }, [
231→    form,
232→    onSubmit,
233→  ]);
234→
235→  useKeyboardShortcut(
236→    {
237→      key: 'Enter',
238→      meta: true,
239→    },
240→    handleSubmit,
241→  );
242→
243→  return (
244→    <Form onSubmit={handleSubmit}>
245→      <FormTextField
246→        label="Name"
247→        value={form.name}
248→        onChange={v =>
249→          setForm(prev => ({
250→            ...prev,
251→            name: v,
252→          }))
253→        }
254→        placeholder="e.g. Email Signature"
255→        error={errors.name}
256→        autoFocus
257→      />
258→      <FormTextField
259→        label="Keyword"
260→        value={form.keyword}
261→        onChange={v =>
262→          setForm(prev => ({
263→            ...prev,
264→            keyword: v,
265→          }))
266→        }
267→        placeholder="e.g. !sig"
268→        description="Type this to expand the snippet"
269→      />
270→      <FormDropdown
271→        label="Category"
272→        value={form.category}
273→        onChange={v => {
274→          if (isSnippetCategory(v)) {
275→            setForm(prev => ({
276→              ...prev,
277→              category: v,
278→            }));
279→          }
280→        }}
281→        options={FORM_CATEGORY_OPTIONS}
282→        placeholder="Select a category"
283→      />
284→      <FormTagPicker
285→        label="Tags"
286→        value={form.tags}
287→        onChange={v =>
288→          setForm(prev => ({
289→            ...prev,
290→            tags: v,
291→          }))
292→        }
293→        options={FORM_TAG_OPTIONS}
294→        placeholder="Add tags..."
295→        description="Categorize your snippet with tags"
296→      />
297→      <FormTextArea
298→        label="Snippet"
299→        value={form.snippet}
300→        onChange={v =>
301→          setForm(prev => ({
302→            ...prev,
303→            snippet: v,
304→          }))
305→        }
306→        placeholder="Enter your snippet content..."
307→        error={errors.snippet}
308→        rows={5}
309→      />
310→    </Form>
311→  );
312→}
