150→        return;
151→      }
152→
153→      switch (e.key) {
154→        case 'ArrowDown':
155→          e.preventDefault();
156→          setActiveIndex(prev =>
157→            prev < availableOptions.length - 1 ? prev + 1 : 0);
158→          break;
159→        case 'ArrowUp':
160→          e.preventDefault();
161→          setActiveIndex(prev =>
162→            prev > 0 ? prev - 1 : availableOptions.length - 1);
163→          break;
164→        case 'Enter':
165→          e.preventDefault();
166→          e.stopPropagation();
167→          if (availableOptions[activeIndex]) {
