169→          }
170→          break;
171→        case 'Escape':
172→          e.preventDefault();
173→          e.stopPropagation();
174→          resetDropdown();
175→          break;
176→        case 'Tab':
177→          resetDropdown();
178→          break;
179→      }
180→    },
181→    [
182→      open,
183→      query,
184→      value,
185→      onChange,
186→      availableOptions,
187→      activeIndex,
188→      selectOption,
189→      resetDropdown,
190→    ],
191→  );
192→
193→  const handleInputChange = useCallback(
194→    (e: React.ChangeEvent<HTMLInputElement>) => {
195→      setQuery(e.target.value);
196→      if (!open) {
197→        setOpen(true);
198→      }
199→    },
200→    [open],
201→  );
202→
203→  const handleInputFocus = useCallback(() => {
204→    if (availableOptions.length > 0) {
205→      setOpen(true);
206→    }
207→  }, [availableOptions.length]);
208→
209→  const getLabel = useCallback(
210→    (optionValue: string) => optionLabelMap.get(optionValue) ?? optionValue,
211→    [optionLabelMap],
212→  );
213→
214→  const activeOption = availableOptions[activeIndex];
215→  const activeOptionId =
216→    open && activeOption
217→      ? `${listboxId}-option-${activeOption.value}`
218→      : undefined;
219→
220→  return (
221→    <FormField
222→      label={label}
223→      description={description}
224→      error={error}
225→      htmlFor={id}
226→    >
227→      <div className="form-tag-picker" ref={containerRef}>
228→        <div
229→          className="form-tag-picker__input-area"
230→          onClick={() => inputRef.current?.focus()}
231→        >
232→          {value.map(v => (
233→            <span key={v} className="form-tag-picker__tag">
234→              <span className="form-tag-picker__tag-label">{getLabel(v)}</span>
235→              <button
236→                type="button"
237→                className="form-tag-picker__tag-remove"
238→                onClick={e => {
239→                  e.stopPropagation();
240→                  removeTag(v);
241→                }}
242→                aria-label={`Remove ${getLabel(v)}`}
243→              >
244→                <svg width="8" height="8" viewBox="0 0 8 8" fill="none">
245→                  <path
246→                    d="M1 1L7 7M7 1L1 7"
247→                    stroke="currentColor"
248→                    strokeWidth="1.5"
249→                    strokeLinecap="round"
250→                  />
251→                </svg>
252→              </button>
253→            </span>
254→          ))}
255→          <input
256→            id={id}
257→            ref={inputRef}
258→            className="form-tag-picker__input"
259→            type="text"
260→            value={query}
261→            onChange={handleInputChange}
262→            onFocus={handleInputFocus}
263→            onKeyDown={handleKeyDown}
264→            placeholder={value.length === 0 ? placeholder : undefined}
265→            autoFocus={autoFocus}
266→            spellCheck={false}
267→            autoComplete="off"
268→            role="combobox"
269→            aria-expanded={open}
270→            aria-controls={open ? listboxId : undefined}
271→            aria-activedescendant={activeOptionId}
272→            aria-invalid={error ? true : undefined}
273→            aria-describedby={error ? `${id}-error` : undefined}
274→          />
275→        </div>
276→        {open && availableOptions.length > 0 && (
277→          <ul
278→            id={listboxId}
279→            ref={menuRef}
280→            className="form-tag-picker__menu"
281→            role="listbox"
282→            aria-label={label}
283→          >
284→            {availableOptions.map((opt, i) => (
285→              <li
286→                key={opt.value}
287→                id={`${listboxId}-option-${opt.value}`}
288→                className={`form-tag-picker__option${i === activeIndex ? ' form-tag-picker__option--active' : ''}`}
289→                role="option"
290→                aria-selected={i === activeIndex}
291→                data-active={i === activeIndex}
292→                onMouseEnter={() => setActiveIndex(i)}
293→                onMouseDown={e => {
294→                  e.preventDefault();
295→                  selectOption(opt.value);
296→                }}
297→              >
298→                {opt.label}
299→              </li>
300→            ))}
301→          </ul>
302→        )}
303→      </div>
304→    </FormField>
305→  );
306→}
