const [editingSnippet, setEditingSnippet] = useState<SnippetEntry | undefined>();
const { items: hudItems, show: showHUD } = useHUD();
const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
```

**Hooks Used:**
- `useState` - state management
- `useEffect` - initialization, cleanup
- `useMemo` - filtering, grouping, options creation
- `useCallback` - event handlers
- `useKeyboardShortcut` - keyboard bindings
- `useNavigation` - breadcrumb management
- `useDbSearch` - full-text search
- `useHUD` - notifications
