### 6. **FORM SUBMISSION & STATE UPDATES**

**Submit Handler:**
```typescript
const handleFormSubmit = useCallback(
  (form: SnippetFormState) => {
    // Map tag values back to tag objects with colors
    const tags = form.tags.map(t => {
      const found = SNIPPET_TAGS.find(st => st.value === t);
      return {
        text: found?.label ?? t,
        color: found?.color,
      };
    });

    if (subView === 'edit' && editingSnippet) {
      // UPDATE PATH
      const updatedEntry: SnippetEntry = {
        ...editingSnippet,
        name: form.name,
        keyword: form.keyword,
        content: form.snippet,
        category: form.category,
        tags,
      };

      setEntries(prev =>
        prev.map(e => (e.id === editingSnippet.id ? updatedEntry : e))
      );

      snippetDb
        .update(editingSnippet.id, {
          name: form.name,
          keyword: form.keyword,
          content: form.snippet,
          category: form.category,
          tags: JSON.stringify(tags),
        })
        .catch(console.error);

      invalidateFts();  // Refresh FTS index
      showHUD({ icon: <SnippetHUDIcon />, title: 'Snippet Updated' });
    } else {
      // CREATE PATH
      const newEntry: SnippetEntry = {
        id: crypto.randomUUID(),
        name: form.name,
        keyword: form.keyword,
        content: form.snippet,
        category: form.category,
        tags,
        createdAt: new Date(),
      };

      setEntries(prev => [newEntry, ...prev]);
      snippetDb.insert(entryToRow(newEntry)).catch(console.error);
      invalidateFts();
      showHUD({ icon: <SnippetHUDIcon />, title: 'Snippet Created' });
    }

    setSubView('list');
    setEditingSnippet(undefined);
  },
  [subView, editingSnippet, showHUD, invalidateFts],
);
```

**Navigation to Forms:**
```typescript
// Create new
