**Initialization from DB:**
```typescript
useEffect(() => {
  let aborted = false;

  snippetDb
    .getAll()
    .then(rows => {
      if (aborted) return;
      if (rows.length > 0) {
        setEntries(rows.map(rowToEntry));
      } else if (!isTauri) {
        // Seed mock data in browser
        const mock = MOCK_SNIPPET_ENTRIES.map(e => ({ ...e }));
        setEntries(mock);
        Promise.all(mock.map(e => snippetDb.insert(entryToRow(e)))).catch(
          console.error,
        );
      }
    })
    .catch(err => {
      console.error('Failed to load snippets:', err);
      if (!isTauri && !aborted) {
        setEntries(MOCK_SNIPPET_ENTRIES.map(e => ({ ...e })));
      }
    });

  return () => {
    aborted = true;
  };
}, []);
